import c4d
import maxon
from maxon.frameworks.nodes import GraphDescription
doc = c4d.documents.GetActiveDocument()
gen = doc.SearchObject('FIO_Probe')
g = GraphDescription.GetGraph(gen)
io_node = None
for c in (g.GetRoot().GetChildren() or []):
    cid = str(c.GetId())
    if '@' in cid and '/' not in cid and cid.split('@')[0] == 'floatingio':
        io_node = c; break
if not io_node: raise RuntimeError('floatingio not found')
print(f'io_node: {io_node.GetId()}')
# Defensively probe attributes one at a time
results = {}
for attr_id in ['net.maxon.attribute.direction', 'net.maxon.node.floatingio.portlist', 'net.maxon.node.floatingio.defaultname.outputs', 'net.maxon.node.floatingio.defaultname.inputs']:
    try:
        val = io_node.GetValue(maxon.Id(attr_id))
        results[attr_id] = repr(val)[:200]
    except Exception as e:
        results[attr_id] = f'<ERR: {str(e)[:100]}>'
print('Attribute probe results:')
for k, v in results.items():
    print(f'  {k}: {v}')
# Also try to find PORTLIST input port and inspect it
for p in (io_node.GetInputs().GetChildren() or []):
    pid = str(p.GetId())
    print(f'  Input port: {pid}')
    # Don't call GetEffectivePortValue (causes 'expected generic datatype capsule')
    # but DO list its child ports if any
    try:
        sub_count = len(list(p.GetChildren() or []))
        print(f'    has {sub_count} sub-children')
    except Exception as e:
        print(f'    children err: {str(e)[:80]}')

import c4d
doc = c4d.documents.GetActiveDocument()
gen = doc.SearchObject('FIO_Probe')
bc = gen.GetData()
print(f'BaseContainer entries on FIO_Probe:')
entries_seen = 0
for i in range(min(bc.GetIndexId(0) + 1, 1) if hasattr(bc, 'GetIndexId') else 0, 0):
    pass  # legacy iteration
# Modern iteration
try:
    for desc_id, value in bc:
        entries_seen += 1
        if entries_seen > 50: break
        try:
            print(f'  [{entries_seen}] desc_id={desc_id}, type={type(value).__name__}, val={repr(value)[:80]}')
        except Exception as e:
            print(f'  [{entries_seen}] err: {e}')
except Exception as e:
    print(f'BC iter err: {e}')
print(f'\nTotal entries: {entries_seen}')
